    render(
      <McpServerSection
        servers={[makeServer({ auth_mode: "static_headers", has_static_headers: true })]}
        {...defaultProps}
      />,
    );
    expect(screen.queryByRole("button", { name: /re-authorize/i })).toBeNull();
  });
});

